// ═══════════════════════════════════════════════════════════════
// Learning Pipeline — 5-step pipeline + 7-layer panel + Full Cycle
// ═══════════════════════════════════════════════════════════════

import { pulseWithCascade } from './learning-graph';
import { showMcpOutput } from './toast';
import {
  LEARNING_BUTTONS, LAYER_BUTTONS, FULL_CYCLE_STEPS,
  STEP_TO_PIPELINE, STEP_TO_LAYERS,
  type LayerButtonDef,
} from './pulse-map';

// ── Individual Pipeline Buttons ───────────────────────────────

function initPipelineButtons() {
  for (const lb of LEARNING_BUTTONS) {
    const btn = document.getElementById(lb.btnId);
    if (!btn) continue;
    btn.dataset.label = lb.label;
    btn.addEventListener('click', async () => {
      btn.textContent = '\u23F3 ' + lb.label + '...';
      btn.setAttribute('disabled', '');
      try {
        const res = await fetch('/api/learning/trigger', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: lb.action }),
        });
        const data = await res.json();
        const ok = data.ok;
        btn.textContent = (ok ? '\u2713 ' : '\u2717 ') + lb.label;
        if (ok) {
          for (const ek of lb.pulseEdges) pulseWithCascade(ek, 0.9);
        }
        if (data.results) {
          const summary = data.results.map((r: { step: string; ok: boolean; output?: string; error?: string }) =>
            `${r.ok ? '\u2713' : '\u2717'} ${r.step}: ${r.output || r.error || ''}`
          ).join('\n');
          showMcpOutput(summary, ok);
        }
      } catch (e) {
        btn.textContent = '\u2717 ' + lb.label;
        console.error('[Learning]', e);
      }
      btn.removeAttribute('disabled');
      setTimeout(() => { btn.textContent = '\u26A1 ' + lb.label; }, 4000);
    });
  }
}

// ── 7-Layer Panel ─────────────────────────────────────────────

async function triggerLayer(lb: LayerButtonDef) {
  const btn = document.getElementById(lb.id);
  if (!btn) return { ok: false };
  btn.textContent = '\u23F3 ' + lb.label + '...';
  btn.setAttribute('disabled', '');
  btn.style.background = 'rgba(250,204,21,0.15)';
  try {
    const res = await fetch('/api/learning/trigger', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action: lb.action }),
    });
    const data = await res.json();
    btn.textContent = (data.ok ? '\u2713 ' : '\u2717 ') + lb.label;
    btn.style.background = data.ok ? 'rgba(16,185,129,0.2)' : 'rgba(239,68,68,0.2)';
    return data;
  } catch {
    btn.textContent = '\u2717 ' + lb.label;
    btn.style.background = 'rgba(239,68,68,0.2)';
    return { ok: false };
  }
}

function resetLayerBtn(lb: LayerButtonDef, delayMs: number) {
  const btn = document.getElementById(lb.id);
  if (!btn) return;
  setTimeout(() => {
    btn.textContent = lb.label;
    btn.style.background = '';
    btn.removeAttribute('disabled');
  }, delayMs);
}

function initLayerButtons() {
  for (const lb of LAYER_BUTTONS) {
    document.getElementById(lb.id)?.addEventListener('click', async () => {
      await triggerLayer(lb);
      resetLayerBtn(lb, 4000);
    });
  }
}

// ── Full Cycle Orchestrator ───────────────────────────────────

function initFullCycle() {
  const fullBtn = document.getElementById('lrn-full-btn');
  if (!fullBtn) return;

  const newFullBtn = fullBtn.cloneNode(true) as HTMLElement;
  fullBtn.parentNode!.replaceChild(newFullBtn, fullBtn);

  newFullBtn.addEventListener('click', async () => {
    newFullBtn.textContent = '\u23F3 Full Cycle...';
    newFullBtn.setAttribute('disabled', '');
    const panel = document.getElementById('layer-panel') as HTMLDetailsElement | null;
    if (panel) panel.open = true;

    const allResults: Array<{ step: string; ok: boolean; output?: string; error?: string }> = [];

    for (const step of FULL_CYCLE_STEPS) {
      const pBtn = document.getElementById(STEP_TO_PIPELINE[step]);
      if (pBtn) { pBtn.style.background = 'rgba(250,204,21,0.15)'; pBtn.textContent = '\u23F3 ' + pBtn.dataset.label; }
      for (const lId of (STEP_TO_LAYERS[step] || [])) {
        const lb = document.getElementById(lId);
        if (lb) { lb.style.background = 'rgba(250,204,21,0.15)'; }
      }

      let stepOk = false;
      let stepResults: any[] = [];
      try {
        const res = await fetch('/api/learning/trigger', {
          method: 'POST', headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ action: step }),
        });
        const data = await res.json();
        stepOk = !!data.ok;
        stepResults = data.results || [];
        for (const r of stepResults) allResults.push(r);
      } catch { stepOk = false; allResults.push({ step, ok: false, error: 'fetch failed' }); }

      const bg = stepOk ? 'rgba(16,185,129,0.2)' : 'rgba(239,68,68,0.2)';
      const icon = stepOk ? '\u2713' : '\u2717';
      if (pBtn) { pBtn.style.background = bg; pBtn.textContent = icon + ' ' + (pBtn.dataset.label || step); }
      for (const lId of (STEP_TO_LAYERS[step] || [])) {
        const lb = document.getElementById(lId);
        if (lb) { lb.style.background = bg; lb.textContent = icon + ' ' + (LAYER_BUTTONS.find(l => l.id === lId)?.label || ''); }
      }
      const matchingLB = LEARNING_BUTTONS.find(l => l.action === step);
      if (stepOk && matchingLB) { for (const ek of matchingLB.pulseEdges) pulseWithCascade(ek, 0.9); }
    }

    const allOk = allResults.every(r => r.ok);
    newFullBtn.textContent = (allOk ? '\u2713' : '\u26A0') + ' Full Cycle';
    const summary = allResults.map(r => `${r.ok ? '\u2713' : '\u2717'} ${r.step}: ${r.output || r.error || ''}`).join('\n');
    showMcpOutput(summary, allOk);

    setTimeout(() => {
      for (const [, id] of Object.entries(STEP_TO_PIPELINE)) {
        const b = document.getElementById(id);
        if (b) { b.style.background = ''; b.textContent = '\u26A1 ' + (b.dataset.label || ''); }
      }
      for (const lb of LAYER_BUTTONS) resetLayerBtn(lb, 0);
      newFullBtn.textContent = '\u26A1 Full Cycle';
      newFullBtn.removeAttribute('disabled');
    }, 6000);
  });
}

// ── Public init ───────────────────────────────────────────────

export function initLearningPipeline() {
  initPipelineButtons();
  initLayerButtons();
  initFullCycle();
}
