// Summary Bar — Header stats and project info
// ═══════════════════════════════════════════════════════════════

let projectName = '';

// Consolidated into learning-graph.ts updateSummaryBar() — no separate header-stats needed

export async function loadProjectInfo() {
  try {
    const res = await fetch('/api/projects');
    const data = await res.json();
    const current = data.projects?.find((p: any) => p.isCurrent);
    if (current) {
      const parts = current.name.split('-').filter(Boolean);
      projectName = parts.length > 3 ? parts.slice(3).join('-') : parts.join('-');
    }
  } catch {}
}
